ALGORITHM SystemCallMechanism
INPUT: systemCallNumber, arguments
OUTPUT: result

BEGIN
 // Invocation
 libraryFunction := GetLibraryFunction(systemCallNumber)
 // Preparation
 preparedArguments := PrepareArguments(arguments)
 // Trap (mode switch)
 TRAP(preparedArguments)
 // Execution
 result := ExecuteSystemCallHandler(systemCallNumber, preparedArguments)
 // Return
 RETURN result
END

#include <unistd.h>

int main() {
