 int bytesRead = read(0, buffer, 10);
 if (bytesRead < 0) {
 perror("read");
 return 1;
 }
 return 0;
}

#include <unistd.h>

void printMessage(const char* message) {
 write(1, message, strlen(message));
}

int main() {
 printMessage("Hello, World!\n");
 return 0;
}
